import { HttpClient, HttpParams } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import { firstValueFrom } from 'rxjs';

import { environment } from '@env';
import { GridListResponse } from '@app/core/models/grid-list-response';
import {
  ActionDTO,
  ActionGridItemDTO,
  SaveActionRequest,
  SaveActionResponse,
  DeleteActionRequest,
  UpdateActionStatusRequest,
} from './action.models';

@Injectable({ providedIn: 'root' })
export class ActionService {
  private readonly http = inject(HttpClient);
  private readonly apiBase = `${environment.apiBaseUrl}/api/v1/actions`;

  // ... methods organized by category
}

getGridList(
  page = 1,
  pageSize = 25,
  search?: string,
  status?: EnumDTO,
): Promise<GridListResponse<ActionGridItemDTO>> {
  return firstValueFrom(
    this.http.post<GridListResponse<ActionGridItemDTO>>(
      `${this.apiBase}/list`,
      { page, pageSize, search, status: status?.name },
    ),
  );
}

get(id: string): Promise<ActionDTO> {
  return firstValueFrom(this.http.get<ActionDTO>(`${this.apiBase}/${id}`));
}

// Save (upsert) — single POST handles both create and update
// Guid.Empty / empty string id = create, valid GUID id = update
save(request: SaveActionRequest): Promise<SaveActionResponse> {
  return firstValueFrom(
    this.http.post<SaveActionResponse>(this.apiBase, request),
  );
}

// Bulk delete via POST
delete(request: DeleteActionRequest): Promise<void> {
  return firstValueFrom(
    this.http.post<void>(`${this.apiBase}/delete`, request),
  );
}

// With typed request body
updateStatus(id: string, request: UpdateActionStatusRequest): Promise<void> {
  return firstValueFrom(
    this.http.put<void>(`${this.apiBase}/${id}/status`, request),
  );
}

// With typed response
setPriority(id: string, request: SetActionPriorityRequest): Promise<SetActionPriorityResponse> {
  return firstValueFrom(
    this.http.put<SetActionPriorityResponse>(`${this.apiBase}/${id}/priority`, request),
  );
}

// No request body (action is the URL)
approve(id: string): Promise<void> {
  return firstValueFrom(this.http.post<void>(`${this.apiBase}/${id}/approve`, {}));
}

escalate(id: string): Promise<void> {
  return firstValueFrom(this.http.post<void>(`${this.apiBase}/${id}/escalate`, {}));
}

// Child status toggle
setEvidenceStatus(actionId: string, evidenceId: string, request: SetActionEvidenceStatusRequest): Promise<SetActionEvidenceStatusResponse> {
  return firstValueFrom(
    this.http.put<SetActionEvidenceStatusResponse>(
      `${this.apiBase}/${actionId}/evidence/${evidenceId}/status`, request,
    ),
  );
}

// Child command
requestConsultation(actionId: string, request: RequestConsultationRequest): Promise<RequestConsultationResponse> {
  return firstValueFrom(
    this.http.post<RequestConsultationResponse>(
      `${this.apiBase}/${actionId}/consultations`, request,
    ),
  );
}

// Child member management
addAssignee(id: string, userId: string): Promise<void> {
  return firstValueFrom(this.http.post<void>(`${this.apiBase}/${id}/assignees`, { userId }));
}

removeAssignee(id: string, userId: string): Promise<void> {
  return firstValueFrom(this.http.delete<void>(`${this.apiBase}/${id}/assignees/${userId}`));
}

// Entity lookups return NamedDTO when shape matches { id, name, description? }
getLookupList(): Promise<NamedDTO[]> {
  return firstValueFrom(
    this.http.get<NamedDTO[]>(`${this.apiBase}/lookup`),
  );
}

// Enum lookups return EnumDTO[]
getStatusOptions(): Promise<EnumDTO[]> {
  return firstValueFrom(
    this.http.get<EnumDTO[]>(`${environment.apiBaseUrl}/api/v1/lookups/action-statuses`),
  );
}

getUniqueNames(excludeId?: string): Promise<string[]> {
  let params = new HttpParams();
  if (excludeId) params = params.set('excludeId', excludeId);
  return firstValueFrom(
    this.http.get<string[]>(`${this.apiBase}/unique-names`, { params }),
  );
}

getComplianceProfileOptions(workflowSlug: string): Promise<ComplianceProfileOption[]> {
  return firstValueFrom(
    this.http.get<ComplianceProfileOption[]>(
      `${environment.apiBaseUrl}/api/v1/compliance-profiles/lookup`,
      { params: new HttpParams().set('workflow', workflowSlug) },
    ),
  );
}

