// core/utils/api-error.util.ts

export interface ProblemDetails {
  type?: string;
  title?: string;
  status?: number;
  detail?: string;
  instance?: string;
  errorCode?: string;
  errors?: Record<string, string[]>;
}

/**
 * Extract a user-facing error message from an API error response.
 * Handles ProblemDetails (RFC 7807) and falls back to a default message.
 */
export function parseApiError(err: unknown, fallback = 'An unexpected error occurred.'): string {
  const httpErr = err as { error?: ProblemDetails };
  if (!httpErr?.error) return fallback;

  const problem = httpErr.error;

  // Validation errors — join field-level messages
  if (problem.errors && Object.keys(problem.errors).length > 0) {
    return Object.values(problem.errors).flat().join(' ');
  }

  // Detail message from the server
  if (problem.detail) return problem.detail;

  // Title as last resort
  if (problem.title) return problem.title;

  return fallback;
}

/**
 * Extract the error code for programmatic handling (e.g., ACTION-002).
 */
export function parseApiErrorCode(err: unknown): string | null {
  const httpErr = err as { error?: ProblemDetails };
  return httpErr?.error?.errorCode ?? null;
}

